interface UserSettings {
  theme: "light" | "dark" | "system";
  language: string;
  notifications: boolean;
  emailDigest: "daily" | "weekly" | "never";
  fontSize: number;
}

function updateSettings(
  current: UserSettings,
  updates: Partial<UserSettings>
): UserSettings {
  return { ...current, ...updates };
}

const defaultSettings: UserSettings = {
  theme: "system",
  language: "en",
  notifications: true,
  emailDigest: "weekly",
  fontSize: 16,
};

// User only changed two fields — no need to send the whole object
const updated = updateSettings(defaultSettings, {
  theme: "dark",
  fontSize: 18,
});

console.log(`Theme: ${updated.theme}`);
console.log(`Font size: ${updated.fontSize}`);
console.log(`Language: ${updated.language}`);
console.log(`Notifications: ${updated.notifications}`);

interface User {
  id: number;
  name: string;
  email: string;
  passwordHash: string;    // NEVER send to clients!
  role: string;
  lastLogin: string;
  createdAt: string;
}

// Safe for public API — no sensitive fields
type PublicUser = Omit<User, "passwordHash">;

// Minimal card view — just enough for a list
type UserCard = Pick<User, "id" | "name" | "role">;

// Type-safe function: can't accidentally leak passwordHash
function toPublicUser(user: User): PublicUser {
  const { passwordHash, ...publicData } = user;
  return publicData;
}

const user: User = {
  id: 1, name: "Alice Chen", email: "alice@co.com",
  passwordHash: "$2b$10$...", role: "admin",
  lastLogin: "2024-01-15", createdAt: "2022-01-01",
};

const publicUser = toPublicUser(user);
console.log(`Name: ${publicUser.name}`);
console.log(`Email: ${publicUser.email}`);
console.log(`Role: ${publicUser.role}`);
// console.log(publicUser.passwordHash);  // TypeScript error!

const card: UserCard = { id: user.id, name: user.name, role: user.role };
console.log(`Card: ${card.id} | ${card.name} | ${card.role}`);

type Role = "admin" | "editor" | "viewer" | "billing";
type Permission = "read" | "write" | "delete" | "manage_billing" | "manage_users";

const rolePermissions: Record<Role, Permission[]> = {
  admin:          ["read", "write", "delete", "manage_billing", "manage_users"],
  editor:         ["read", "write"],
  viewer:         ["read"],
  billing:        ["read", "manage_billing"],
};

function hasPermission(role: Role, permission: Permission): boolean {
  return rolePermissions[role].includes(permission);
}

function getPermissionSummary(role: Role): string {
  return `${role}: [${rolePermissions[role].join(", ")}]`;
}

const rolesToCheck: Role[] = ["admin", "editor", "viewer", "billing"];
for (const role of rolesToCheck) {
  console.log(getPermissionSummary(role));
}

console.log(`Can editor delete? ${hasPermission("editor", "delete")}`);
console.log(`Can admin manage users? ${hasPermission("admin", "manage_users")}`);

// Imagine these are functions from a library you don't control
function createOrder(customerId: number, product: string, quantity: number, unitPrice: number) {
  return {
    id: `ORD-${Date.now()}`,
    customerId,
    product,
    quantity,
    total: quantity * unitPrice,
    status: "pending" as const,
    createdAt: "2024-01-15",
  };
}

function getOrderSummary(order: ReturnType<typeof createOrder>) {
  return `${order.product} x${order.quantity} = $${order.total}`;
}

// Extract parameter types — useful for validation, mocking, logging
type CreateOrderParams = Parameters<typeof createOrder>;
// [customerId: number, product: string, quantity: number, unitPrice: number]

function logOrderCreation(params: CreateOrderParams): void {
  const [customerId, product, quantity] = params;
  console.log(`Creating order: ${quantity}x ${product} for customer ${customerId}`);
}

const params: CreateOrderParams = [42, "TypeScript Pro", 3, 99];
logOrderCreation(params);

const order = createOrder(...params);
console.log(getOrderSummary(order));
console.log(`Status: ${order.status}`);
